  1	import { Button, Popper } from '@patternfly/react-core';
  2	import { CogIcon } from '@patternfly/react-icons';
  3	import * as React from 'react';
  4	import { useTranslation } from 'react-i18next';
  5	import { FlowScope, MetricType, StatFunction } from '../../model/flow-query';
  6	import { ScopeConfigDef } from '../../model/scope';
  7	import { TopologyOptions } from '../../model/topology';
  8	import { useOutsideClickEvent } from '../../utils/outside-hook';
  9	import './topology-display-dropdown.css';
 10	import { TopologyDisplayOptions } from './topology-display-options';
 11	
 12	export const TopologyDisplayDropdown: React.FC<{
 13	  metricFunction: StatFunction;
 14	  setMetricFunction: (f: StatFunction) => void;
 15	  metricType: MetricType;
 16	  setMetricType: (t: MetricType) => void;
 17	  metricScope: FlowScope;
 18	  setMetricScope: (s: FlowScope) => void;
 19	  topologyOptions: TopologyOptions;
 20	  setTopologyOptions: (o: TopologyOptions) => void;
 21	  allowedTypes: MetricType[];
 22	  scopes: ScopeConfigDef[];
 23	}> = ({
 24	  metricFunction,
 25	  setMetricFunction,
 26	  metricType,
 27	  setMetricType,
 28	  metricScope,
 29	  setMetricScope,
 30	  topologyOptions,
 31	  setTopologyOptions,
 32	  allowedTypes,
 33	  scopes
 34	}) => {
 35	  const { t } = useTranslation('plugin__netobserv-plugin');
 36	  const containerRef = React.useRef<HTMLDivElement>(null);
 37	  const triggerRef = React.useRef<HTMLButtonElement>(null);
 38	  const popperRef = React.useRef<HTMLDivElement>(null);
 39	  const [isOpen, setOpen] = React.useState<boolean>(false);
 40	
 41	  const ref = useOutsideClickEvent(() => setOpen(false));
 42	
 43	  const trigger = React.useCallback(() => {
 44	    return (
 45	      <Button
 46	        ref={triggerRef}
 47	        variant="link"
 48	        icon={<CogIcon />}
 49	        onClick={() => setOpen(!isOpen)}
 50	        data-test="display-dropdown-button"
 51	      >
 52	        {t('Display options')}
 53	      </Button>
 54	    );
 55	  }, [isOpen, t]);
 56	
 57	  const popper = React.useCallback(() => {
 58	    return (
 59	      <div id="topology-display-popper" ref={popperRef} className="pf-v6-c-menu" role="dialog">
 60	        <TopologyDisplayOptions
 61	          metricFunction={metricFunction}
 62	          setMetricFunction={setMetricFunction}
 63	          metricType={metricType}
 64	          setMetricType={setMetricType}
 65	          metricScope={metricScope}
 66	          setMetricScope={setMetricScope}
 67	          topologyOptions={topologyOptions}
 68	          setTopologyOptions={setTopologyOptions}
 69	          allowedTypes={allowedTypes}
 70	          scopes={scopes}
 71	        />
 72	      </div>
 73	    );
 74	  }, [
 75	    metricFunction,
 76	    setMetricFunction,
 77	    metricType,
 78	    setMetricType,
 79	    metricScope,
 80	    setMetricScope,
 81	    topologyOptions,
 82	    setTopologyOptions,
 83	    allowedTypes,
 84	    scopes
 85	  ]);
 86	
 87	  return (
 88	    <div id="display-dropdown-container" data-test="display-dropdown-container" ref={ref}>
 89	      <div ref={containerRef}>
 90	        <Popper
 91	          trigger={trigger()}
 92	          triggerRef={triggerRef}
 93	          popper={popper()}
 94	          popperRef={popperRef}
 95	          isVisible={isOpen}
 96	          enableFlip={true}
 97	          appendTo={containerRef.current || undefined}
 98	        />
 99	      </div>
100	    </div>
101	  );
102	};
103	
104	export default TopologyDisplayDropdown;

